// lib/exchange.ts
export async function getExchangeRate(toCurrency: string) {
    if (toCurrency === "BRL") return 1;
  
    try {
      // Busca a cotação de BRL para a moeda desejada (ex: BRL-USD)
      const response = await fetch(`https://economia.awesomeapi.com.br/json/last/BRL-${toCurrency}`);
      const data = await response.json();
      
      // A API retorna algo como BRLUSD: { bid: "0.20" }
      const key = `BRL${toCurrency}`;
      return parseFloat(data[key].bid);
    } catch (error) {
      console.error("Erro ao buscar cotação:", error);
      return 1; // Retorna 1 caso falhe para não quebrar os cálculos
    }
  }